#define ROC_ALIGNOF(T) alignof(T)
#define ROC_STATIC_ASSERT(cond, message) static_assert(cond, message)
#else
#define ROC_ALIGNAS(n) _Alignas(n)
#define ROC_ALIGNOF(T) _Alignof(T)
#define ROC_STATIC_ASSERT(cond, message) _Static_assert(cond, message)
#endif

